    25→// Allows graceful handling of missing configuration for ECDS.
    26→class MissingConfigFilter : public Http::PassThroughDecoderFilter {
    27→public:
    28→  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap&, bool) override {
    29→    decoder_callbacks_->streamInfo().setResponseFlag(
    30→        StreamInfo::CoreResponseFlag::NoFilterConfigFound);
    31→    decoder_callbacks_->sendLocalReply(Http::Code::InternalServerError, EMPTY_STRING, nullptr,
    32→                                       absl::nullopt, EMPTY_STRING);
    33→    return Http::FilterHeadersStatus::StopIteration;
    34→  }
    35→};
    36→
    37→static Http::FilterFactoryCb MissingConfigFilterFactory =
    38→    [](Http::FilterChainFactoryCallbacks& cb) {
    39→      cb.addStreamDecoderFilter(std::make_shared<MissingConfigFilter>());
    40→    };
