    68→template <class FilterCtx, class NeutralNamedHttpFilterFactory>
    69→class FilterChainHelper : Logger::Loggable<Logger::Id::config> {
    70→public:
    71→  using FilterFactoriesList = FilterChainUtility::FilterFactoriesList;
    72→  using FilterConfigProviderManager =
    73→      Filter::FilterConfigProviderManager<Filter::NamedHttpFilterFactoryCb, FilterCtx>;
    74→
    75→  FilterChainHelper(FilterConfigProviderManager& filter_config_provider_manager,
    76→                    Server::Configuration::ServerFactoryContext& server_context,
    77→                    Upstream::ClusterManager& cluster_manager, FilterCtx& factory_context,
    78→                    const std::string& stats_prefix)
    79→      : filter_config_provider_manager_(filter_config_provider_manager),
    80→        server_context_(server_context), cluster_manager_(cluster_manager),
    81→        factory_context_(factory_context), stats_prefix_(stats_prefix) {}
    82→
    83→  using FiltersList = Protobuf::RepeatedPtrField<
    84→      envoy::extensions::filters::network::http_connection_manager::v3::HttpFilter>;
    85→
    86→  // Process the filters in this filter chain.
    87→  absl::Status processFilters(const FiltersList& filters, const std::string& prefix,
    88→                              const std::string& filter_chain_type,
    89→                              FilterFactoriesList& filter_factories) {
    90→
    91→    DependencyManager dependency_manager;
    92→    for (int i = 0; i < filters.size(); i++) {
    93→      absl::Status status =
    94→          processFilter(filters[i], i, prefix, filter_chain_type, i == filters.size() - 1,
    95→                        filter_factories, dependency_manager);
    96→      if (!status.ok()) {
    97→        return status;
    98→      }
    99→    }
   100→    // TODO(auni53): Validate encode dependencies too.
   101→    return dependency_manager.validDecodeDependencies();
   102→  }
   103→
   104→private:
   105→  absl::Status
   106→  processFilter(const envoy::extensions::filters::network::http_connection_manager::v3::HttpFilter&
   107→                    proto_config,
   108→                int i, const std::string& prefix, const std::string& filter_chain_type,
   109→                bool last_filter_in_current_config, FilterFactoriesList& filter_factories,
   110→                DependencyManager& dependency_manager) {
   111→    ENVOY_LOG(debug, "    {} filter #{}", prefix, i);
   112→
   113→    const bool disabled_by_default = proto_config.disabled();
   114→
   115→    // Ensure the terminal filter will not be disabled by default. Because the terminal filter must
   116→    // be the last filter in the chain (ensured by 'validateTerminalFilters') and terminal flag of
   117→    // dynamic filter could not determined and may changed at runtime, so we check the last filter
   118→    // flag here as alternative.
   119→    if (last_filter_in_current_config && disabled_by_default) {
   120→      return absl::InvalidArgumentError(fmt::format(
   121→          "Error: the last (terminal) filter ({}) in the chain cannot be disabled by default.",
   122→          proto_config.name()));
   123→    }
   124→
   125→    if (proto_config.config_type_case() ==
   126→        envoy::extensions::filters::network::http_connection_manager::v3::HttpFilter::
   127→            ConfigTypeCase::kConfigDiscovery) {
   128→      return processDynamicFilterConfig(proto_config.name(), proto_config.config_discovery(),
   129→                                        filter_factories, filter_chain_type,
   130→                                        last_filter_in_current_config, disabled_by_default);
   131→    }
   132→
   133→    // Now see if there is a factory that will accept the config.
   134→    auto* factory = Config::Utility::getAndCheckFactory<NeutralNamedHttpFilterFactory>(
   135→        proto_config, proto_config.is_optional());
   136→    // null pointer returned only when the filter is optional, then skip all the processes.
   137→    if (factory == nullptr) {
   138→      ENVOY_LOG(warn, "Didn't find a registered factory for the optional http filter {}",
   139→                proto_config.name());
   140→      return absl::OkStatus();
   141→    }
   142→    ProtobufTypes::MessagePtr message = Config::Utility::translateToFactoryConfig(
   143→        proto_config, server_context_.messageValidationVisitor(), *factory);
   144→    absl::StatusOr<Http::FilterFactoryCb> callback_or_error =
   145→        factory->createFilterFactoryFromProto(*message, stats_prefix_, factory_context_);
   146→    if (!callback_or_error.status().ok()) {
   147→      return callback_or_error.status();
   148→    }
   149→    Http::FilterFactoryCb callback = callback_or_error.value();
   150→    dependency_manager.registerFilter(factory->name(), *factory->dependencies());
   151→    const bool is_terminal = factory->isTerminalFilterByProto(*message, server_context_);
   152→    Config::Utility::validateTerminalFilters(proto_config.name(), factory->name(),
   153→                                             filter_chain_type, is_terminal,
   154→                                             last_filter_in_current_config);
   155→    auto filter_config_provider = filter_config_provider_manager_.createStaticFilterConfigProvider(
   156→        {factory->name(), callback}, proto_config.name());
   157→#ifdef ENVOY_ENABLE_YAML
   158→    ENVOY_LOG(debug, "      name: {}", filter_config_provider->name());
   159→    ENVOY_LOG(debug, "    config: {}",
   160→              MessageUtil::getJsonStringFromMessageOrError(
   161→                  static_cast<const Protobuf::Message&>(proto_config.typed_config())));
   162→#endif
   163→    filter_factories.push_back({std::move(filter_config_provider), disabled_by_default});
   164→    return absl::OkStatus();
   165→  }
